#include <iostream>
using namespace std;

int main() {
  int value = 42;
  int* ptr = &value;

  cout << "Value: " << value << endl;
  cout << "Address: " << ptr << endl;
  cout << "Dereference: " << *ptr << endl;

  *ptr = 100;  // Modify via pointer
  cout << "Modified value: " << value << endl;
  return 0;
}
